from fastapi import FastAPIfrom fastapi.staticfiles import StaticFilesfrom fastapi.middleware.cors import CORSMiddlewarefrom dotenv import load_dotenvfrom database import engine, Basefrom routers import projects, library, items, export, templatesload_dotenv()Base.metadata.create_all(bind=engine)app = FastAPI(title="Flyer Maker")app.add_middleware(    CORSMiddleware,    allow_origins=["*"],    allow_methods=["*"],    allow_headers=["*"],)app.include_router(projects.router, prefix="/projects", tags=["projects"])app.include_router(library.router, prefix="/library", tags=["library"])app.include_router(items.router, prefix="/items", tags=["items"])app.include_router(export.router, prefix="/export", tags=["export"])app.include_router(templates.router, prefix="/templates", tags=["templates"])app.mount("/static", StaticFiles(directory="static"), name="static")app.mount("/uploads", StaticFiles(directory="uploads"), name="uploads")app.mount("/outputs", StaticFiles(directory="outputs"), name="outputs")